update cmp_bankelectronicreceipt a
INNER JOIN cmp_bankreconciliation b ON a.enterprisebankaccount = b.bankaccount
                                          and a.bankseqno = b.bank_seq_no
                                          and a.tran_amt = b.tran_amt
                                          and a.dc_flag = b.dc_flag
set a.bankreconciliationid = b.id,
a.associationstatus = 0
WHERE
(a.associationstatus = 4 or a.associationstatus is null) and
a.enterprisebankaccount in

    #{item}

AND a.trandate BETWEEN #{startDate}
AND #{endDate}
AND a.ytenant_id = #{ytenantId}
AND b.ytenant_id = #{ytenantId}

    AND b.id in

        #{item}

